INSERT INTO programme_prioritaire (id, code, nom, domaine, finalite) VALUES
('PR-P01', 'PR-P01', 'Cadre Légal et Réglementaire et Gouvernance du Numérique', 'Gouvernance, droit, régulation, confiance numérique', 'Renforcer le cadre juridique et institutionnel pour assurer le développement de l''économie numérique tout en garantissant la confiance numérique'),
('PR-P02', 'PR-P02', 'Infrastructures, Réseaux et Connectivité Universelle', 'Télécoms, fibre, réseaux mobiles, connectivité', 'Garantir un accès universel à une connectivité de qualité, performante et à moindre coût'),
('PR-P03', 'PR-P03', 'Souveraineté Numérique et Cyberrésilience', 'Cybersécurité, résilience, protection des données critiques', 'Assurer la protection des infrastructures, services et données critiques, pour l''administration et les usagers (entreprises et citoyens)'),
('PR-P04', 'PR-P04', 'Plateforme Publique Numérique (e-ID, e-Sign, e-Payment, etc.)', 'Identité numérique, signature électronique, paiement électronique, interopérabilité', 'Fournir un socle numérique de base, fournissant des services partagés à vocation transversale et centrale'),
('PR-P05', 'PR-P05', 'Modernisation du Système d''Information de l''Etat (Interopérabilité, AEG, E-Gov, Collab)', 'SI Etat, urbanisation, e-Gov, collaboration administrative', 'Assurer l''urbanisation et la rationalisation du SI Etat, permettant d''assurer la cohérence, l''interopérabilité et la sécurité des applications et services à destination de l''administration et des usagers'),
('PR-P06', 'PR-P06', 'Dématérialisation des procédures administratives', 'Administration digitale, services publics, simplification usager', 'Eriger une administration simple, performante, orientée services et centrée sur l''usager.'),
('PR-P07', 'PR-P07', 'Développement des compétences et renforcement des capacités numériques', 'Formation, certification, culture numérique, talents', 'Développer l''expertise dans les métiers du numérique et promouvoir la culture digitale des populations'),
('PR-P08', 'PR-P08', 'Sénégal Digital Factory: De l''idée au produit', 'Startups, produits numériques, innovation, prototypage', 'Accompagner les startups, les PMI et les PME afin de promouvoir l''innovation technologique et l''émergence de champions du numérique'),
('PR-P09', 'PR-P09', 'Promotion, Investissement et Financement du Numérique', 'Financement, FONSIS, capital-risque, fonds d''investissement', 'Promouvoir un cadre attractif pour les investissements dans le numérique et mobiliser les financements adaptés au secteur du numérique à travers des instruments de cofinancement impliquant les fonds du FONSIS, le nouveau pôle des institutions financières publiques, ainsi que les marchés de capitaux et les fonds d''investissement régionaux'),
('PR-P10', 'PR-P10', 'Sénégal Villes Intelligentes (Smart, Safe & Secure Cities)', 'Smart cities, sécurité urbaine, IoT, gestion urbaine', 'Favoriser l''utilisation des technologies intelligentes dans l''amélioration du service public, la sécurité et le bien-être des populations'),
('PR-P11', 'PR-P11', 'Déclinaison Sectorielle du Numérique (e-Cadastre, e-Santé, e-Education, e-Finances, e-Agri, e-Commerce, etc.)', 'Santé, éducation, agriculture, finances, commerce, transport', 'Assurer la performance des différents secteurs d''activités par l''intégration du numérique dans les différents processus métiers.'),
('PR-P12', 'PR-P12', 'Digitalisation du secteur informel et des micro entreprises (Outils, bancarisation, identification, localisation, etc.)', 'Informel, inclusion numérique, identification, localisation', 'Accompagner la transformation du secteur informel par la diffusion du numérique afin que les usages au quotidien constituent un avantage compétitif.')
